<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Ubuntu-ish Desktop</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  html, body { width: 100%; height: 100%; overflow: hidden; }
  body {
    font-family: "Ubuntu", "Segoe UI", system-ui, sans-serif;
    color: #f2f2f2;
    user-select: none;
  }

  /* ---------- Desktop ---------- */
  #desktop {
    position: fixed;
    inset: 0;
    background:
      radial-gradient(circle at 25% 20%, #5a2d4d 0%, transparent 55%),
      radial-gradient(circle at 80% 75%, #772f3a 0%, transparent 55%),
      linear-gradient(135deg, #2c001e 0%, #3c1029 45%, #77216f 100%);
    overflow: hidden;
  }

  #desktop-info {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    text-align: center;
    color: rgba(255,255,255,0.28);
    pointer-events: none;
  }
  #desktop-info h1 { font-size: 44px; font-weight: 300; letter-spacing: 2px; }
  #desktop-info p { margin-top: 8px; font-size: 15px; }

  /* ---------- Taskbar / Dock ---------- */
  #taskbar {
    position: absolute;
    top: 0;
    left: 0;
    right: 0;
    height: 40px;
    background: rgba(20, 12, 20, 0.85);
    backdrop-filter: blur(8px);
    border-bottom: 1px solid rgba(255,255,255,0.08);
    display: flex;
    align-items: center;
    gap: 6px;
    padding: 0 10px;
    z-index: 9000;
  }
  #taskbar .brand {
    display: flex; align-items: center; gap: 8px;
    font-weight: 600; font-size: 14px; margin-right: 12px;
    color: #e95420;
  }
  #taskbar .brand .dot {
    width: 14px; height: 14px; border-radius: 50%;
    background: #e95420;
    box-shadow: 0 0 0 3px rgba(233,84,32,0.25);
  }
  .launcher {
    display: flex; align-items: center; gap: 8px;
    background: rgba(255,255,255,0.06);
    border: 1px solid rgba(255,255,255,0.08);
    color: #f2f2f2;
    padding: 6px 12px;
    border-radius: 6px;
    font-size: 13px;
    cursor: pointer;
    transition: background 0.15s;
  }
  .launcher:hover { background: rgba(233,84,32,0.35); }
  .launcher .ico { font-size: 15px; }
  #clock {
    margin-left: auto;
    font-size: 13px;
    font-variant-numeric: tabular-nums;
    opacity: 0.85;
  }

  /* ---------- Windows ---------- */
  .window {
    position: absolute;
    min-width: 360px;
    min-height: 240px;
    width: 640px;
    height: 440px;
    background: #2b2b2b;
    border: 1px solid rgba(0,0,0,0.5);
    border-radius: 8px;
    box-shadow: 0 18px 50px rgba(0,0,0,0.55);
    display: none;
    flex-direction: column;
    overflow: hidden;
    z-index: 100;
  }
  .window.open { display: flex; }

  .titlebar {
    height: 38px;
    flex: 0 0 38px;
    background: linear-gradient(#3a3a3a, #303030);
    border-bottom: 1px solid rgba(0,0,0,0.4);
    display: flex;
    align-items: center;
    padding: 0 10px;
    gap: 8px;
    cursor: move;
  }
  .titlebar .title { font-size: 13px; font-weight: 600; flex: 1; }
  .titlebar .win-close {
    width: 16px; height: 16px; border-radius: 50%;
    background: #e95420; border: none; cursor: pointer;
    color: #2b2b2b; font-size: 11px; line-height: 16px; font-weight: 700;
    display: flex; align-items: center; justify-content: center;
  }
  .titlebar .win-close:hover { filter: brightness(1.2); }
  .titlebar .fake-dots { display: flex; gap: 6px; }
  .titlebar .fake-dots span {
    width: 12px; height: 12px; border-radius: 50%; background: #555;
  }

  .win-body { flex: 1; display: flex; flex-direction: column; overflow: hidden; }

  /* ---------- Files app ---------- */
  #files-window .toolbar {
    display: flex; align-items: center; gap: 8px;
    padding: 8px; background: #333;
    border-bottom: 1px solid rgba(0,0,0,0.4);
  }
  .tool-btn {
    background: rgba(255,255,255,0.08);
    border: 1px solid rgba(255,255,255,0.08);
    color: #f2f2f2; padding: 5px 10px; border-radius: 5px;
    cursor: pointer; font-size: 13px;
  }
  .tool-btn:hover { background: rgba(255,255,255,0.16); }
  #files-path {
    flex: 1;
    background: #1e1e1e;
    border: 1px solid rgba(0,0,0,0.5);
    border-radius: 5px;
    padding: 6px 10px;
    font-family: "Ubuntu Mono", monospace;
    font-size: 13px;
    color: #9cdcfe;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
  }
  #files-list {
    flex: 1;
    overflow-y: auto;
    padding: 10px;
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(96px, 1fr));
    gap: 6px;
    align-content: start;
  }
  .fs-item {
    display: flex; flex-direction: column; align-items: center;
    gap: 6px; padding: 10px 6px; border-radius: 6px;
    cursor: pointer; text-align: center;
    transition: background 0.1s;
  }
  .fs-item:hover { background: rgba(255,255,255,0.08); }
  .fs-item.selected { background: rgba(233,84,32,0.4); }
  .fs-item .glyph { font-size: 34px; line-height: 1; }
  .fs-item .name {
    font-size: 12px; word-break: break-word; max-width: 90px;
  }
  #files-empty {
    grid-column: 1 / -1;
    text-align: center;
    opacity: 0.5;
    font-size: 13px;
    padding: 20px;
  }

  /* ---------- Notepad app ---------- */
  #tabs {
    display: flex; align-items: stretch;
    background: #262626;
    border-bottom: 1px solid rgba(0,0,0,0.4);
    overflow-x: auto;
    min-height: 34px;
  }
  #tabs::-webkit-scrollbar { height: 6px; }
  .tab {
    display: flex; align-items: center; gap: 8px;
    padding: 6px 10px;
    font-size: 12px;
    border-right: 1px solid rgba(0,0,0,0.35);
    background: #2f2f2f;
    cursor: pointer;
    white-space: nowrap;
    max-width: 180px;
  }
  .tab:hover { background: #3a3a3a; }
  .tab.active { background: #1e1e1e; color: #e95420; }
  .tab .tab-name { overflow: hidden; text-overflow: ellipsis; }
  .tab .tab-close {
    border: none; background: transparent; color: inherit;
    cursor: pointer; font-size: 13px; line-height: 1;
    opacity: 0.6; padding: 0 2px;
  }
  .tab .tab-close:hover { opacity: 1; color: #e95420; }
  #new-tab {
    border: none; background: transparent; color: #f2f2f2;
    font-size: 18px; cursor: pointer; padding: 0 14px;
    flex: 0 0 auto;
  }
  #new-tab:hover { color: #e95420; }
  #editor {
    flex: 1;
    width: 100%;
    resize: none;
    border: none;
    outline: none;
    background: #1e1e1e;
    color: #eaeaea;
    font-family: "Ubuntu Mono", "Consolas", monospace;
    font-size: 14px;
    line-height: 1.5;
    padding: 12px;
  }
</style>
</head>
<body>
<div id="desktop">
  <div id="desktop-info">
    <h1>Ubuntu Desktop</h1>
    <p>Launch an app from the bar above</p>
  </div>

  <!-- Taskbar -->
  <div id="taskbar">
    <div class="brand"><span class="dot"></span> focal</div>
    <button id="open-files" class="launcher"><span class="ico">📁</span> Files</button>
    <button id="open-notepad" class="launcher"><span class="ico">📝</span> Notepad</button>
    <div id="clock">--:--</div>
  </div>

  <!-- Files window -->
  <div id="files-window" class="window" style="left:120px; top:80px;">
    <div class="titlebar">
      <button class="win-close" title="Close">✕</button>
      <span class="fake-dots"><span></span><span></span></span>
      <span class="title">Files</span>
    </div>
    <div class="win-body">
      <div class="toolbar">
        <button id="files-up" class="tool-btn" title="Parent folder">↑ Up</button>
        <div id="files-path">/</div>
      </div>
      <div id="files-list"></div>
    </div>
  </div>

  <!-- Notepad window -->
  <div id="notepad-window" class="window" style="left:300px; top:120px;">
    <div class="titlebar">
      <button class="win-close" title="Close">✕</button>
      <span class="fake-dots"><span></span><span></span></span>
      <span class="title">Notepad</span>
    </div>
    <div class="win-body">
      <div style="display:flex; align-items:stretch;">
        <div id="tabs" style="flex:1;"></div>
        <button id="new-tab" title="New tab">＋</button>
      </div>
      <textarea id="editor" placeholder="Start typing..." spellcheck="false"></textarea>
    </div>
  </div>
</div>

<script>
(function () {
  "use strict";

  /* ============ Window management (open/close/focus/drag) ============ */
  let zTop = 100;
  function focusWindow(win) { win.style.zIndex = ++zTop; }

  function openWindow(win) {
    win.classList.add("open");
    focusWindow(win);
  }
  function closeWindow(win) { win.classList.remove("open"); }

  document.querySelectorAll(".window").forEach(function (win) {
    win.addEventListener("mousedown", function () { focusWindow(win); });
    win.querySelector(".win-close").addEventListener("click", function () {
      closeWindow(win);
    });
    // Dragging via titlebar
    var bar = win.querySelector(".titlebar");
    var dragging = false, offX = 0, offY = 0;
    bar.addEventListener("mousedown", function (e) {
      if (e.target.classList.contains("win-close")) return;
      dragging = true;
      var r = win.getBoundingClientRect();
      offX = e.clientX - r.left;
      offY = e.clientY - r.top;
      focusWindow(win);
      e.preventDefault();
    });
    document.addEventListener("mousemove", function (e) {
      if (!dragging) return;
      var x = e.clientX - offX;
      var y = e.clientY - offY;
      y = Math.max(40, y); // keep below taskbar
      x = Math.min(Math.max(0, x), window.innerWidth - 80);
      y = Math.min(y, window.innerHeight - 40);
      win.style.left = x + "px";
      win.style.top = y + "px";
    });
    document.addEventListener("mouseup", function () { dragging = false; });
  });

  var filesWin = document.getElementById("files-window");
  var notepadWin = document.getElementById("notepad-window");
  document.getElementById("open-files").addEventListener("click", function () {
    openWindow(filesWin);
  });
  document.getElementById("open-notepad").addEventListener("click", function () {
    openWindow(notepadWin);
    renderTabs();
  });

  /* ============ Files app ============ */
  // Static fake Linux filesystem. Folders are objects, files are strings.
  var FS = {
    bin: { bash: "", ls: "", cat: "", grep: "", nano: "" },
    boot: { "vmlinuz-5.15": "", "initrd.img": "" },
    dev: { null: "", zero: "", sda1: "" },
    etc: {
      "hostname": "", "hosts": "", "passwd": "", "fstab": "",
      apt: { "sources.list": "" },
      ssh: { "sshd_config": "" }
    },
    home: {
      user: {
        Documents: {
          "resume.pdf": "",
          "todo.txt": "",
          Projects: { "app.html": "", "notes.md": "" }
        },
        Downloads: { "ubuntu.iso": "", "install.sh": "" },
        Pictures: { "wallpaper.png": "", "avatar.jpg": "" },
        Music: { "song.mp3": "" },
        ".bashrc": "",
        ".profile": ""
      }
    },
    lib: { "libc.so.6": "" },
    media: {},
    mnt: {},
    opt: { google: {} },
    root: { ".bashrc": "" },
    sbin: { init: "", reboot: "" },
    tmp: { "cache.tmp": "" },
    usr: {
      bin: { python3: "", node: "", git: "" },
      lib: {},
      local: { bin: {} },
      share: { doc: {} }
    },
    var: {
      log: { "syslog": "", "auth.log": "" },
      www: { html: { "index.html": "" } },
      cache: {}
    }
  };

  var currentPath = []; // array of segment names; [] === "/"
  var pathEl = document.getElementById("files-path");
  var listEl = document.getElementById("files-list");

  function nodeAt(segments) {
    var node = FS;
    for (var i = 0; i < segments.length; i++) {
      if (node && typeof node === "object" && segments[i] in node) {
        node = node[segments[i]];
      } else {
        return null;
      }
    }
    return node;
  }

  function isFolder(node) { return node && typeof node === "object"; }

  function pathString() {
    return "/" + currentPath.join("/");
  }

  function renderFiles() {
    pathEl.textContent = currentPath.length ? "/" + currentPath.join("/") : "/";
    var node = nodeAt(currentPath) || {};
    listEl.innerHTML = "";

    var names = Object.keys(node);
    // folders first, then files, each alphabetical
    names.sort(function (a, b) {
      var fa = isFolder(node[a]) ? 0 : 1;
      var fb = isFolder(node[b]) ? 0 : 1;
      if (fa !== fb) return fa - fb;
      return a.localeCompare(b);
    });

    if (names.length === 0) {
      var empty = document.createElement("div");
      empty.id = "files-empty";
      empty.textContent = "(empty folder)";
      listEl.appendChild(empty);
      return;
    }

    names.forEach(function (name) {
      var folder = isFolder(node[name]);
      var item = document.createElement("div");
      item.className = "fs-item";
      item.dataset.name = name;
      item.dataset.folder = folder ? "1" : "0";

      var glyph = document.createElement("div");
      glyph.className = "glyph";
      glyph.textContent = folder ? "📁" : "📄";

      var label = document.createElement("div");
      label.className = "name";
      label.textContent = name;

      item.appendChild(glyph);
      item.appendChild(label);

      item.addEventListener("click", function () {
        listEl.querySelectorAll(".fs-item.selected").forEach(function (el) {
          el.classList.remove("selected");
        });
        item.classList.add("selected");
      });
      item.addEventListener("dblclick", function () {
        if (folder) {
          currentPath.push(name);
          renderFiles();
        }
      });

      listEl.appendChild(item);
    });
  }

  document.getElementById("files-up").addEventListener("click", function () {
    if (currentPath.length) {
      currentPath.pop();
      renderFiles();
    }
  });

  renderFiles();

  /* ============ Notepad app (tabbed, localStorage) ============ */
  var STORAGE_KEY = "ubuntu_notepad_v1";
  var tabsEl = document.getElementById("tabs");
  var editor = document.getElementById("editor");
  var state = loadState();

  function loadState() {
    try {
      var raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        var parsed = JSON.parse(raw);
        if (parsed && Array.isArray(parsed.tabs) && parsed.tabs.length) {
          if (typeof parsed.active !== "number" ||
              parsed.active < 0 || parsed.active >= parsed.tabs.length) {
            parsed.active = 0;
          }
          return parsed;
        }
      }
    } catch (e) { /* fall through to default */ }
    return { tabs: [{ title: "untitled", content: "" }], active: 0 };
  }

  function saveState() {
    try { localStorage.setItem(STORAGE_KEY, JSON.stringify(state)); }
    catch (e) { /* ignore quota errors */ }
  }

  function renderTabs() {
    tabsEl.innerHTML = "";
    state.tabs.forEach(function (tab, idx) {
      var el = document.createElement("div");
      el.className = "tab" + (idx === state.active ? " active" : "");

      var name = document.createElement("span");
      name.className = "tab-name";
      name.textContent = tab.title || "untitled";
      el.appendChild(name);

      var close = document.createElement("button");
      close.className = "tab-close";
      close.textContent = "×";
      close.title = "Close tab";
      close.addEventListener("click", function (e) {
        e.stopPropagation();
        closeTab(idx);
      });
      el.appendChild(close);

      el.addEventListener("click", function () {
        state.active = idx;
        syncEditor();
        renderTabs();
        saveState();
      });

      tabsEl.appendChild(el);
    });
    syncEditor();
  }

  function syncEditor() {
    var tab = state.tabs[state.active];
    editor.value = tab ? tab.content : "";
  }

  function deriveTitle(content) {
    var firstLine = (content.split("\n")[0] || "").trim();
    if (!firstLine) return "untitled";
    return firstLine.length > 20 ? firstLine.slice(0, 20) + "…" : firstLine;
  }

  function closeTab(idx) {
    state.tabs.splice(idx, 1);
    if (state.tabs.length === 0) {
      state.tabs.push({ title: "untitled", content: "" });
      state.active = 0;
    } else if (state.active >= state.tabs.length) {
      state.active = state.tabs.length - 1;
    } else if (idx < state.active) {
      state.active--;
    }
    renderTabs();
    saveState();
  }

  document.getElementById("new-tab").addEventListener("click", function () {
    state.tabs.push({ title: "untitled", content: "" });
    state.active = state.tabs.length - 1;
    renderTabs();
    saveState();
    editor.focus();
  });

  editor.addEventListener("input", function () {
    var tab = state.tabs[state.active];
    if (!tab) return;
    tab.content = editor.value;
    tab.title = deriveTitle(editor.value);
    // update the active tab label live
    var activeEl = tabsEl.children[state.active];
    if (activeEl) {
      activeEl.querySelector(".tab-name").textContent = tab.title;
    }
    saveState();
  });

  renderTabs();

  /* ============ Clock ============ */
  var clockEl = document.getElementById("clock");
  function tick() {
    var d = new Date();
    var h = String(d.getHours()).padStart(2, "0");
    var m = String(d.getMinutes()).padStart(2, "0");
    clockEl.textContent = h + ":" + m;
  }
  tick();
  setInterval(tick, 15000);
})();
</script>
</body>
</html>
